using namespace std;
int main(){long long x;scanf("%lld",&x);long long d=1;while(x>d){x-=d;d++;}if(d%2==1)printf("%lld/%lld\n",d-x+1,x);else printf("%lld/%lld\n",x,d-x+1);}
